import requests
import json
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth
import sys


class RabbitMQManager:
    def __init__(self, host: str = "localhost", port: int = 15672, 
                 username: str = "guest", password: str = "guest"):
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(username, password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        headers = {"Content-Type": "application/json"}
        
        try:
            if method == "GET":
                response = self.session.get(url, headers=headers)
            elif method == "PUT":
                response = self.session.put(url, headers=headers, 
                                           data=json.dumps(data) if data else None)
            elif method == "DELETE":
                response = self.session.delete(url, headers=headers)
            elif method == "POST":
                response = self.session.post(url, headers=headers, 
                                            data=json.dumps(data) if data else None)
            
            response.raise_for_status()
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error making {method} request to {endpoint}: {e}")
            raise
    
    def create_vhost(self, vhost_name: str) -> bool:
        print(f"Creating virtual host: {vhost_name}")
        try:
            self._make_request("PUT", f"vhosts/{vhost_name}")
            print(f"Virtual host '{vhost_name}' created successfully")
            return True
        except Exception as e:
            print(f"Failed to create vhost '{vhost_name}': {e}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f"Deleting virtual host: {vhost_name}")
        try:
            self._make_request("DELETE", f"vhosts/{vhost_name}")
            print(f"Virtual host '{vhost_name}' deleted successfully")
            return True
        except Exception as e:
            print(f"Failed to delete vhost '{vhost_name}': {e}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        try:
            response = self._make_request("GET", "vhosts")
            vhosts = response.json()
            print(f"\nExisting virtual hosts ({len(vhosts)}):")
            for vhost in vhosts:
                print(f"  - {vhost['name']}")
            return vhosts
        except Exception as e:
            print(f"Failed to list vhosts: {e}")
            return []
    
    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        print(f"Creating user: {username}")
        data = {
            "password": password,
            "tags": tags
        }
        try:
            self._make_request("PUT", f"users/{username}", data)
            print(f"User '{username}' created successfully with tags: {tags}")
            return True
        except Exception as e:
            print(f"Failed to create user '{username}': {e}")
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f"Deleting user: {username}")
        try:
            self._make_request("DELETE", f"users/{username}")
            print(f"User '{username}' deleted successfully")
            return True
        except Exception as e:
            print(f"Failed to delete user '{username}': {e}")
            return False
    
    def list_users(self) -> List[Dict]:
        try:
            response = self._make_request("GET", "users")
            users = response.json()
            print(f"\nExisting users ({len(users)}):")
            for user in users:
                print(f"  - {user['name']} (tags: {user.get('tags', '')})")
            return users
        except Exception as e:
            print(f"Failed to list users: {e}")
            return []
    
    def set_permissions(self, username: str, vhost: str, 
                       configure: str = ".*", write: str = ".*", 
                       read: str = ".*") -> bool:
        print(f"Setting permissions for user '{username}' on vhost '{vhost}'")
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        try:
            self._make_request("PUT", f"permissions/{vhost}/{username}", data)
            print(f"Permissions set: configure='{configure}', write='{write}', read='{read}'")
            return True
        except Exception as e:
            print(f"Failed to set permissions: {e}")
            return False
    
    def clear_permissions(self, username: str, vhost: str) -> bool:
        print(f"Clearing permissions for user '{username}' on vhost '{vhost}'")
        try:
            self._make_request("DELETE", f"permissions/{vhost}/{username}")
            print(f"Permissions cleared successfully")
            return True
        except Exception as e:
            print(f"Failed to clear permissions: {e}")
            return False
    
    def list_permissions(self, vhost: Optional[str] = None, 
                        username: Optional[str] = None) -> List[Dict]:
        try:
            if vhost and username:
                response = self._make_request("GET", f"permissions/{vhost}/{username}")
                perms = [response.json()]
            elif vhost:
                response = self._make_request("GET", f"vhosts/{vhost}/permissions")
                perms = response.json()
            elif username:
                response = self._make_request("GET", f"users/{username}/permissions")
                perms = response.json()
            else:
                response = self._make_request("GET", "permissions")
                perms = response.json()
            
            print(f"\nPermissions ({len(perms)}):")
            for perm in perms:
                print(f"  - User: {perm['user']}, VHost: {perm['vhost']}")
                print(f"    Configure: {perm['configure']}")
                print(f"    Write: {perm['write']}")
                print(f"    Read: {perm['read']}")
            return perms
        except Exception as e:
            print(f"Failed to list permissions: {e}")
            return []
    
    def set_topic_permissions(self, username: str, vhost: str, 
                             exchange: str, write: str = ".*", 
                             read: str = ".*") -> bool:
        print(f"Setting topic permissions for user '{username}' on vhost '{vhost}'")
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        try:
            self._make_request("PUT", f"topic-permissions/{vhost}/{username}", data)
            print(f"Topic permissions set for exchange '{exchange}'")
            return True
        except Exception as e:
            print(f"Failed to set topic permissions: {e}")
            return False
    
    def setup_multi_tenant_environment(self, tenants: List[Dict]) -> bool:
        print("\n" + "="*60)
        print("Setting up Multi-Tenant RabbitMQ Environment")
        print("="*60)
        
        success = True
        
        for tenant in tenants:
            tenant_name = tenant.get("name")
            vhost_name = tenant.get("vhost", tenant_name)
            users_config = tenant.get("users", [])
            
            print(f"\n--- Configuring Tenant: {tenant_name} ---")
            
            if not self.create_vhost(vhost_name):
                success = False
                continue
            
            for user_config in users_config:
                username = user_config.get("username")
                password = user_config.get("password")
                tags = user_config.get("tags", "")
                permissions = user_config.get("permissions", {})
                
                if not self.create_user(username, password, tags):
                    success = False
                    continue
                
                configure = permissions.get("configure", ".*")
                write = permissions.get("write", ".*")
                read = permissions.get("read", ".*")
                
                if not self.set_permissions(username, vhost_name, 
                                           configure, write, read):
                    success = False
        
        print("\n" + "="*60)
        if success:
            print("Multi-tenant environment setup completed successfully!")
        else:
            print("Multi-tenant environment setup completed with some errors.")
        print("="*60)
        
        return success
    
    def get_overview(self) -> Dict:
        try:
            response = self._make_request("GET", "overview")
            overview = response.json()
            print("\nRabbitMQ Overview:")
            print(f"  RabbitMQ Version: {overview.get('rabbitmq_version', 'N/A')}")
            print(f"  Erlang Version: {overview.get('erlang_version', 'N/A')}")
            print(f"  Cluster Name: {overview.get('cluster_name', 'N/A')}")
            return overview
        except Exception as e:
            print(f"Failed to get overview: {e}")
            return {}


